import React from 'react';

const Menu = ({header, items, active, setActive}) => {
    return(
        <header className={active ? 'header fixed active' : 'header'} onClick={() => setActive(false)}>
            <div className="container">
                <div className="header_inner" onClick={e => e.stopPropagation()}>
                    <a className="logo" href="/">MoGo</a>

                    <nav className="nav">
                            <ul>
                                {items.map(item =>
                                    <li>
                                        <a href={item.href}>{item.value}</a>
                                    </li>
                                )}
                            </ul>
                    </nav>

                    <button className="nav_toggle" type="menu">
                        <i className="fa-solid fa-bars"></i>
                    </button>
                </div>
            </div>
        </header>
    );
}

export default Menu;
